export type LogEvent =
    // Boot & lifecycle
    | { event: 'boot-start' }
    | { event: 'boot-ready'; ms: number; view: string }
    | { event: 'init-crash'; message: string; stack: string; ms: number }
    | { event: 'crash-detected'; lastAction: string; lastView: string; lastPage: number }
    | { event: 'restore-none' }
    | { event: 'restore-start'; view: string; galleryId: number | null; hasQuery: boolean }
    | { event: 'restore-ok'; view: string; galleryId?: number }
    | { event: 'restore-fallback'; view: string; reason: string }
    | { event: 'resume'; kind: string; elapsedMs: number }
    | { event: 'refresh-index-failed'; message: string }
    // Navigation
    | { event: 'view-push'; from: string; to: string }
    | { event: 'view-pop'; from: string; to: string }
    | { event: 'view-transition'; from: string; to: string; frameMs: number }
    // Pagination
    | { event: 'page-change'; view: string; from: number; to: number; totalItems: number }
    // Search & favorites
    | { event: 'filter-load-failed'; error: string }
    | { event: 'search-failed'; error: string }
    | { event: 'favorites-load-failed'; error: string }
    | { event: 'queries-load-failed'; error: string }
    // Artists
    | { event: 'artists-loaded'; count: number }
    | { event: 'artists-load-failed'; error: string }
    | { event: 'artists-enqueue'; type: string; line: string }
    | { event: 'artists-add-ok'; line: string; status: string }
    | { event: 'artists-remove-start'; line: string }
    | { event: 'artists-remove-ok'; line: string }
    | { event: 'artists-remove-poll'; phase: string }
    | { event: 'artists-op-failed'; type: string; line: string; error: string }
    // Database
    | { event: 'db-error'; op: string; error: string }
    // Global errors
    | { event: 'uncaught-error'; message: string; source: string; line: number; col: number; stack: string }
    | { event: 'unhandled-rejection'; message: string; stack: string };

type EventName = LogEvent['event'];
type PayloadOf<E extends EventName> = Omit<Extract<LogEvent, { event: E }>, 'event'>;
type HasPayload<E extends EventName> = keyof PayloadOf<E> extends never ? false : true;

export type LogEmit = <E extends EventName>(
    ...args: HasPayload<E> extends true ? [event: E, data: PayloadOf<E>] : [event: E]
) => void;

export class LogService {
    private cleanups: (() => void)[] = [];

    start(): void {
        if (typeof window === 'undefined') return;

        const onError = (event: ErrorEvent) => {
            this.emit('uncaught-error', {
                message: event.message,
                source: event.filename ?? '',
                line: event.lineno ?? 0,
                col: event.colno ?? 0,
                stack: event.error?.stack ?? '',
            });
        };

        const onRejection = (event: PromiseRejectionEvent) => {
            const reason = event.reason;
            this.emit('unhandled-rejection', {
                message: String(reason?.message ?? reason),
                stack: reason?.stack ?? '',
            });
        };

        window.addEventListener('error', onError);
        window.addEventListener('unhandledrejection', onRejection);
        this.cleanups.push(
            () => window.removeEventListener('error', onError),
            () => window.removeEventListener('unhandledrejection', onRejection),
        );
    }

    emit: LogEmit = ((event: string, data?: Record<string, unknown>) => {
        fetch('/api/log', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ event, data }),
        }).catch(() => {});
    }) as LogEmit;

    destroy(): void {
        for (const cleanup of this.cleanups) cleanup();
        this.cleanups = [];
    }
}


// FILE: gallery-app/src/lib/state/index.svelte.ts
import { PAGE_SIZE, RESUME_RECOVERY_MS, DEEP_SLEEP_MS } from '../config.js';
import type { PaginatedGallerySource, ViewMode } from '../types.js';
import * as api from '../services/api.js';
import { LogService } from '../services/LogService.js';
import { setDbLogger } from '../services/db.js';
import { getJson, setJson, remove } from '../services/storage.js';
import { ToastState } from './toast.svelte.js';
import { UIState } from './ui.svelte.js';
import { SearchState } from './search.svelte.js';
import { ReaderState } from './reader.svelte.js';
import { FavoritesState } from './favorites.svelte.js';
import { SavedState } from './saved.svelte.js';
import { DeleteState } from './delete.svelte.js';
import { ArtistsState } from './artists.svelte.js';
import { saveSession, loadSession, clearSession, type SessionSnapshot } from './session.js';

class AppState {
    readonly log = new LogService();
    toast = new ToastState();
    ui: UIState;
    searchState: SearchState;
    favorites: FavoritesState;
    saved: SavedState;
    reader: ReaderState;
    delete_: DeleteState;
    artists: ArtistsState;

    private lastTick = Date.now();
    private tickInterval: ReturnType<typeof setInterval> | undefined;
    private cleanups: (() => void)[] = [];
    private scrollTimer: ReturnType<typeof setTimeout> | undefined;

    constructor() {
        const emit = this.log.emit;
        this.ui = new UIState(emit);
        this.searchState = new SearchState(emit);
        this.favorites = new FavoritesState(emit);
        this.saved = new SavedState(emit);
        this.reader = new ReaderState(this.ui);
        this.delete_ = new DeleteState({
            favorites: this.favorites,
            reader: this.reader,
            search: this.searchState,
        });
        this.artists = new ArtistsState(this.toast, emit);
        this.ui.onViewChange = () => this.persistSession();
    }

    async init() {
        const t0 = Date.now();

        // LogService owns global error handlers — start first so crashes during init are captured
        this.log.start();
        this.log.emit('boot-start');

        // Crash sentinel: detect if previous session died without clean shutdown
        const sentinel = getJson<{ action: string; view: string; page: number } | null>('sentinel', null);
        if (sentinel) {
            this.log.emit('crash-detected', {
                lastAction: sentinel.action,
                lastView: sentinel.view,
                lastPage: sentinel.page,
            });
        }
        setJson('sentinel', { action: 'boot', view: 'list', page: 0 });

        // Clean shutdown clears the sentinel
        const onBeforeUnload = () => remove('sentinel');
        window.addEventListener('beforeunload', onBeforeUnload);
        document.addEventListener('visibilitychange', () => {
            if (document.visibilityState === 'hidden') remove('sentinel');
        });
        this.cleanups.push(() => window.removeEventListener('beforeunload', onBeforeUnload));

        // Wire db module's logger to our LogService
        setDbLogger((op, error) => this.log.emit('db-error', { op, error }));

        try {
            await Promise.all([
                this.saved.init(),
                this.favorites.init(),
                this.reader.loadProgress(),
                this.artists.init(),
            ]);

            api.refreshIndex().catch((e) =>
                this.log.emit('refresh-index-failed', { message: String(e) }),
            );

            await this.searchState.loadFilterOptions();

            await this.restoreSession();

            this.setupResumeDetection();
            this.setupScrollPersistence();

            this.log.emit('boot-ready', { ms: Date.now() - t0, view: this.ui.viewMode });
        } catch (e) {
            this.log.emit('init-crash', {
                message: String((e as Error)?.message ?? e),
                stack: (e as Error)?.stack ?? '',
                ms: Date.now() - t0,
            });
        }
    }

    /** Update crash sentinel before expensive operations. */
    updateSentinel(action: string) {
        setJson('sentinel', { action, view: this.ui.viewMode, page: this.searchState.currentPage });
    }

    /** Single owner of page-change orchestration: log, sentinel, persist, scroll. */
    changePage(view: ViewMode, source: PaginatedGallerySource, page: number) {
        this.log.emit('page-change', { view, from: source.currentPage, to: page, totalItems: source.totalPages * PAGE_SIZE });
        this.updateSentinel(`page-change:${view}:${page}`);
        source.currentPage = page;
        this.persistSession();
        document.getElementById(`view-${view}`)?.scrollTo(0, 0);
    }

    /** Single owner of search→persist flow. */
    async searchAndPersist(searchFn: () => Promise<void>) {
        this.ui.pushView('list');
        await searchFn();
        this.persistSession();
    }

    // -- Cross-domain orchestration --

    async replaySearch(galleryId: number) {
        const query = this.favorites.getQuery(galleryId);
        if (!query) return;

        await this.searchState.restoreFromQuery(query);

        const idx = this.searchState.allGalleries.findIndex(g => g.gallery_id === galleryId);
        if (idx >= 0) {
            this.searchState.currentPage = Math.floor(idx / PAGE_SIZE);
        }

        this.ui.pushView('list');

        setTimeout(() => {
            const container = document.getElementById('view-list');
            const el = container?.querySelector(`#gallery-${galleryId}`) as HTMLElement | null;
            if (el) {
                el.scrollIntoView({ behavior: 'auto', block: 'center' });
                el.classList.add('replay-highlight');
                setTimeout(() => el.classList.remove('replay-highlight'), 1500);
            }
        }, 100);
    }

    openFavorites() {
        this.ui.pushView('favorites');
        this.favorites.loadGalleries();
    }

    // -- Session persistence --

    /** Debounced session persist — call freely, writes at most every 500ms. */
    persistSession() {
        clearTimeout(this.scrollTimer);
        this.scrollTimer = setTimeout(() => this.flushSession(), 500);
    }

    /** Immediate write — used by persistSession debounce and destroy. */
    private flushSession() {
        clearTimeout(this.scrollTimer);
        saveSession({
            viewMode: this.ui.viewMode,
            viewStack: this.ui.viewStack,
            activeGalleryId: this.reader.activeGallery?.gallery_id,
            searchQuery: this.searchState.fullQuery || undefined,
            searchPage: this.searchState.currentPage || undefined,
            favoritesPage: this.favorites.currentPage || undefined,
            listScroll: document.getElementById('view-list')?.scrollTop || undefined,
            favoritesScroll: document.getElementById('view-favorites')?.scrollTop || undefined,
        });
    }

    private async restoreSession() {
        const snap = loadSession();
        if (!snap) {
            this.log.emit('restore-none');
            await this.searchState.search('');
            return;
        }

        this.log.emit('restore-start', {
            view: snap.viewMode,
            galleryId: snap.activeGalleryId ?? null,
            hasQuery: !!snap.searchQuery,
        });

        clearSession();

        // Restore search if we had one
        if (snap.searchQuery) {
            await this.searchState.restoreFromQuery(snap.searchQuery);
            if (snap.searchPage) {
                this.searchState.currentPage = snap.searchPage;
            }
        } else {
            await this.searchState.search('');
        }

        // Restore view based on saved mode
        switch (snap.viewMode) {
            case 'reader':
                if (snap.activeGalleryId != null) {
                    // IDB progress is the single owner of persistent position data —
                    // always fresher than the session snapshot (which only updates on view changes)
                    const position = this.reader.getProgress(snap.activeGalleryId);
                    try {
                        await this.reader.restoreReader(snap.activeGalleryId, position);
                        this.ui.setViewDirect('reader', snap.viewStack);
                        await this.prepareBackViews(snap);
                        this.persistSession();
                        this.log.emit('restore-ok', { view: 'reader', galleryId: snap.activeGalleryId });
                        return;
                    } catch (e) {
                        this.log.emit('restore-fallback', { view: 'reader', reason: String((e as Error)?.message ?? e) });
                    }
                }
                // Fallback to list
                break;

            case 'favorites':
                this.ui.setViewDirect('favorites', snap.viewStack);
                await this.favorites.loadGalleries();
                if (snap.favoritesPage) {
                    this.favorites.currentPage = snap.favoritesPage;
                }
                this.restoreScrollPositions(snap);
                this.persistSession();
                this.log.emit('restore-ok', { view: 'favorites' });
                return;

            case 'saved':
                this.ui.setViewDirect('saved', snap.viewStack);
                this.persistSession();
                this.log.emit('restore-ok', { view: 'saved' });
                return;

            case 'list':
                // Already restored search above, just stay in list
                break;
        }

        this.restoreScrollPositions(snap);
        this.persistSession();
        this.log.emit('restore-ok', { view: 'list' });
    }

    private restoreScrollPositions(snap: SessionSnapshot) {
        requestAnimationFrame(() => {
            if (snap.listScroll) {
                const listView = document.getElementById('view-list');
                if (listView) listView.scrollTop = snap.listScroll;
            }
            if (snap.favoritesScroll) {
                const favsView = document.getElementById('view-favorites');
                if (favsView) favsView.scrollTop = snap.favoritesScroll;
            }
        });
    }

    /**
     * Pre-position back views so swipe-back reveals the correct scroll position.
     * During normal usage the DOM owns scroll position (views stay mounted).
     * On restore the DOM is fresh — derive position from the active gallery.
     */
    private async prepareBackViews(snap: SessionSnapshot) {
        if (!snap.activeGalleryId) return;

        const backView = snap.viewStack[snap.viewStack.length - 1];

        if (backView === 'favorites') {
            await this.favorites.loadGalleries();
            // Derive the correct page from the gallery's position in the list
            const idx = this.favorites.favoriteGalleries.findIndex(
                g => g.gallery_id === snap.activeGalleryId
            );
            if (idx >= 0) {
                this.favorites.currentPage = Math.floor(idx / PAGE_SIZE);
            }
            this.scrollViewToGallery('view-favorites', snap.activeGalleryId);
        } else if (backView === 'list') {
            this.scrollViewToGallery('view-list', snap.activeGalleryId);
        }
    }

    /** Scroll a view container to center a gallery row, and sync its thumbnail strip. */
    private scrollViewToGallery(viewId: string, galleryId: number) {
        const pageIndex = this.reader.getProgress(galleryId).pageIndex;
        requestAnimationFrame(() => {
            const container = document.getElementById(viewId);
            const el = container?.querySelector(`#gallery-${galleryId}`);
            if (el) {
                el.scrollIntoView({ block: 'center' });
            }
            // Also sync the strip to current page (reader.syncStripScroll needs
            // peekBack() which requires the reader view to be active — do it directly)
            this.reader.syncStripScroll(galleryId, pageIndex);
        });
    }

    private setupScrollPersistence() {
        const onScroll = () => this.persistSession();
        const listView = document.getElementById('view-list');
        const favsView = document.getElementById('view-favorites');
        listView?.addEventListener('scroll', onScroll, { passive: true });
        favsView?.addEventListener('scroll', onScroll, { passive: true });
        this.cleanups.push(
            () => listView?.removeEventListener('scroll', onScroll),
            () => favsView?.removeEventListener('scroll', onScroll),
        );
    }

    // -- Resume detection --

    private onVisibilityChange = () => {
        if (document.visibilityState === 'visible') {
            this.handleResume();
        }
    };

    private setupResumeDetection() {
        document.addEventListener('visibilitychange', this.onVisibilityChange);

        // iOS sentinel: detect deep sleep via tick drift
        this.lastTick = Date.now();
        this.tickInterval = setInterval(() => {
            const now = Date.now();
            const drift = now - this.lastTick;
            this.lastTick = now;
            if (drift > 3000) {
                this.handleResume();
            }
        }, 1000);
    }

    destroy() {
        this.flushSession();
        this.log.destroy();
        clearInterval(this.tickInterval);
        clearTimeout(this.scrollTimer);
        document.removeEventListener('visibilitychange', this.onVisibilityChange);
        for (const fn of this.cleanups) fn();
        this.cleanups = [];
        this.reader.destroy();
        this.toast.destroy();
    }

    private handleResume() {
        const snap = loadSession();
        if (!snap) return;

        const elapsed = Date.now() - this.lastTick;

        if (elapsed > DEEP_SLEEP_MS) {
            this.log.emit('resume', { kind: 'deep-sleep', elapsedMs: elapsed });
            this.toast.show('Session expired, refreshing...');
            this.searchState.search(this.searchState.currentQuery);
            return;
        }

        if (elapsed > RESUME_RECOVERY_MS) {
            this.log.emit('resume', { kind: 'recovery', elapsedMs: elapsed });
            this.searchState.search(this.searchState.currentQuery);
        }
    }
}

export const appState = new AppState();


// FILE: gallery-app/src/lib/state/reader.svelte.ts
import { THUMB_WIDTH } from '../config.js';
import type { Gallery, GalleryListItem, PagePosition } from '../types.js';
import * as api from '../services/api.js';
import * as db from '../services/db.js';
import type { UIState } from './ui.svelte.js';

const scheduleIdle = globalThis.requestIdleCallback ?? ((cb: () => void) => setTimeout(cb, 0));

let sessionCounter = 0;

/** Owns all resources for one open→close reader cycle. */
export class ReaderSession {
    readonly id: number;
    readonly gallery: Gallery;
    readonly abortController: AbortController;
    readonly blobUrls = new Map<number, string>();
    readonly loadingPages = new Set<number>();
    private readonly timers = new Set<ReturnType<typeof setTimeout>>();
    private readonly rafIds = new Set<number>();
    private observer: IntersectionObserver | null = null;
    private scrollCleanup: (() => void) | null = null;
    private _dropped = false;

    constructor(gallery: Gallery) {
        this.id = ++sessionCounter;
        this.gallery = gallery;
        this.abortController = new AbortController();
    }

    get signal(): AbortSignal {
        return this.abortController.signal;
    }

    get isDropped(): boolean {
        return this._dropped;
    }

    addBlobUrl(pageIndex: number, url: string) {
        if (this._dropped) {
            URL.revokeObjectURL(url);
            return;
        }
        this.blobUrls.set(pageIndex, url);
    }

    hasPage(pageIndex: number): boolean {
        return this.blobUrls.has(pageIndex);
    }

    markLoading(pageIndex: number) {
        this.loadingPages.add(pageIndex);
    }

    unmarkLoading(pageIndex: number) {
        this.loadingPages.delete(pageIndex);
    }

    isLoading(pageIndex: number): boolean {
        return this.loadingPages.has(pageIndex);
    }

    setObserver(obs: IntersectionObserver) {
        this.observer?.disconnect();
        this.observer = obs;
    }

    setScrollCleanup(fn: () => void) {
        this.scrollCleanup?.();
        this.scrollCleanup = fn;
    }

    addTimer(id: ReturnType<typeof setTimeout>): ReturnType<typeof setTimeout> {
        if (this._dropped) {
            clearTimeout(id);
            return id;
        }
        this.timers.add(id);
        return id;
    }

    clearTimer(id: ReturnType<typeof setTimeout>) {
        clearTimeout(id);
        this.timers.delete(id);
    }

    addRaf(id: number): number {
        if (this._dropped) {
            cancelAnimationFrame(id);
            return id;
        }
        this.rafIds.add(id);
        return id;
    }

    clearRaf(id: number) {
        cancelAnimationFrame(id);
        this.rafIds.delete(id);
    }

    /** Deterministic cleanup — idempotent. */
    drop() {
        if (this._dropped) return;
        this._dropped = true;

        this.abortController.abort();

        this.observer?.disconnect();
        this.observer = null;

        this.scrollCleanup?.();
        this.scrollCleanup = null;

        for (const t of this.timers) clearTimeout(t);
        this.timers.clear();

        for (const r of this.rafIds) cancelAnimationFrame(r);
        this.rafIds.clear();

        for (const url of this.blobUrls.values()) URL.revokeObjectURL(url);
        this.blobUrls.clear();

        this.loadingPages.clear();
    }
}

export class ReaderState {
    session = $state<ReaderSession | null>(null);
    currentPosition = $state<PagePosition>({ pageIndex: 0, fraction: 0 });
    progress = $state<Record<number, PagePosition>>({});

    private ui: UIState;
    private debounceTimers = new Map<number, ReturnType<typeof setTimeout>>();
    private _lastSyncedPageIndex = -1;

    constructor(ui: UIState) {
        this.ui = ui;
    }

    /** Backward-compat readonly getter for templates and session persistence. */
    get activeGallery(): Gallery | null {
        return this.session?.gallery ?? null;
    }

    get currentPageIndex(): number {
        return this.currentPosition.pageIndex;
    }

    async loadProgress() {
        this.progress = await db.getAllProgress();
    }

    getProgress(galleryId: number): PagePosition {
        return this.progress[galleryId] ?? { pageIndex: 0, fraction: 0 };
    }

    getProgressIndex(galleryId: number): number {
        return this.progress[galleryId]?.pageIndex ?? 0;
    }

    async openReader(item: GalleryListItem, startPage: number) {
        // Drop previous session if still alive
        this.session?.drop();

        const gallery = await api.getGallery(item.gallery_id);
        const s = new ReaderSession(gallery);
        this.session = s;

        const position: PagePosition = { pageIndex: startPage, fraction: 0 };
        this._lastSyncedPageIndex = -1;
        this.currentPosition = position;
        this.saveProgress(gallery.gallery_id, position);
        this.ui.pushView('reader');
    }

    closeReader() {
        // Capture local reference — the idle callback can never touch this.session
        const closingSession = this.session;
        this.session = null;
        this.ui.popView();
        scheduleIdle(() => closingSession?.drop());
    }

    saveProgress(galleryId: number, position: PagePosition) {
        // Only write $state when page actually changes
        if (position.pageIndex !== this._lastSyncedPageIndex) {
            this._lastSyncedPageIndex = position.pageIndex;
            this.progress[galleryId] = position;
            this.currentPosition = position;
            this.syncStripScroll(galleryId, position.pageIndex);
        }

        // Debounce IDB writes (250ms trailing edge)
        const existing = this.debounceTimers.get(galleryId);
        if (existing != null) clearTimeout(existing);
        this.debounceTimers.set(galleryId, setTimeout(() => {
            this.debounceTimers.delete(galleryId);
            db.setProgress(galleryId, position);
        }, 250));
    }

    removeProgress(ids: Set<number>) {
        const newProgress = { ...this.progress };
        for (const id of ids) {
            delete newProgress[id];
            const timer = this.debounceTimers.get(id);
            if (timer != null) {
                clearTimeout(timer);
                this.debounceTimers.delete(id);
            }
        }
        this.progress = newProgress;
    }

    destroy() {
        this.session?.drop();
        for (const timer of this.debounceTimers.values()) clearTimeout(timer);
        this.debounceTimers.clear();
    }

    /** Silently scroll the thumbnail strip in the hidden back view to match current page. */
    syncStripScroll(galleryId: number, pageIndex: number) {
        const rawTarget = pageIndex * THUMB_WIDTH;
        this.ui.stripScrolls[galleryId] = rawTarget;

        const backView = this.ui.peekBack();
        const viewId = backView ? `view-${backView}` : null;
        if (!viewId) return;

        const container = document.getElementById(viewId);
        const row = container?.querySelector(`#gallery-${galleryId}`) as HTMLElement | null;
        const strip = row?.querySelector('.row-strip') as HTMLElement;
        if (strip) {
            const centered = rawTarget - (strip.clientWidth / 2) + (THUMB_WIDTH / 2);
            strip.scrollLeft = Math.max(0, centered);
        }
    }

    async restoreReader(galleryId: number, position: PagePosition): Promise<boolean> {
        const gallery = await api.getGallery(galleryId);
        const s = new ReaderSession(gallery);
        this.session = s;
        this._lastSyncedPageIndex = -1;
        this.currentPosition = position;
        return true;
    }
}


